package automation

import (
	"context"

	"google.golang.org/grpc"

	"github.snooguts.net/reddit/devplatform-api/go/grpc/devvit/reddit/v2alpha"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/actor/automation"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/grpc/proxyutil"
)

type OnModMailProxy struct {
	automation.UnimplementedOnModMailServer
	client automation.OnModMailClient
}

func init() {
	proxyutil.Register(&automation.OnModMail_ServiceDesc, NewOnModMailProxy)
}
func NewOnModMailProxy(cc grpc.ClientConnInterface) automation.OnModMailServer {
	return &OnModMailProxy{client: automation.NewOnModMailClient(cc)}
}
func (p *OnModMailProxy) OnModMail(ctx context.Context, in *v2alpha.ModMail) (*automation.HandlerResult, error) {
	return proxyutil.ProxyMethod[v2alpha.ModMail, automation.HandlerResult](p.client.OnModMail)(ctx, in)
}
